fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len() as i64;
    let mut graph = vec![vec![]; n as usize];

    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let cost = edge[2];
        if online[u] && online[v] {
            graph[u].push((v, cost));
        }
    }

    let mut max_score = -1;
    let mut pq = std::collections::BinaryHeap::new();
    pq.push((-i64::MAX, 0, 0));
    let mut visited = vec![false; n as usize];

    while let Some((min_edge_neg, node, cost)) = pq.pop() {
        let min_edge = -min_edge_neg;
        if visited[node as usize] {
            continue;
        }
        visited[node as usize] = true;

        if node == n - 1 {
            max_score = std::cmp::max(max_score, min_edge);
            continue;
        }

        for (neighbor, edge_cost) in &graph[node as usize] {
            let new_cost = cost + edge_cost;
            if new_cost <= k {
                let new_min_edge = std::cmp::min(min_edge, edge_cost);
                pq.push((-new_min_edge, *neighbor, new_cost));
            }
        }
    }

    max_score
}
